// defaultLayerID returns the first layer's id, or 0 if the map has no
// layers yet (the JS handles 0 by refusing to paint). Layers ordered by
// ord asc, so [0] is the base layer for stock maps.
func defaultLayerID(layers []maps.Layer) int64 {
	if len(layers) == 0 {
		return 0
	}
	return layers[0].ID
}

// defaultLayerName mirrors defaultLayerID for the status bar.
func defaultLayerName(layers []maps.Layer) string {
	if len(layers) == 0 {
		return "no layer"
	}
	return layers[0].Name
}

