// lockedCountLabel pluralizes the count chip; matches the staged-changes
// convention in the palette panel.
func lockedCountLabel(n int) string {
	if n == 1 {
		return "1 cell locked"
	}
	return fmt.Sprintf("%d cells locked", n)
}

// defaultTileLayerIDAttr returns the id of the lowest-ord tile layer as
// a string for the sample-patch panel to fall back on when the layer
// picker isn't wired (the panel POSTs this id when no other source is
// available; see mapmaker-procedural.js). "" when no tile layer exists.
func defaultTileLayerIDAttr(p MapmakerProps) string {
	for _, l := range p.Layers {
		if l.Kind == "tile" {
			return fmt.Sprintf("%d", l.ID)
		}
	}
	return ""
}

// MapPublicBadge moved to LEVEL in the holistic redesign — the level
// editor's settings tab owns the public toggle now. The badge struct
// + helpers were removed; if/when the level editor wants a clickable
// badge in its header, the same shape can be re-introduced under
// `LevelPublicBadge`.

// proceduralInitialSeed returns the persisted seed, or 1 as a sensible
// non-zero default so the first preview produces something deterministic.
func proceduralInitialSeed(m maps.Map) int64 {
	if m.Seed != nil {
		return *m.Seed
	}
	return 1
}

// stagedChipLabel pluralizes the staged-changes chip in the palette.
// Singular gets a neat "1 staged change"; everything else "{n} staged changes".
func stagedChipLabel(n int) string {
	if n == 1 {
		return "1 staged change"
	}
	return fmt.Sprintf("%d staged changes", n)
}

// paletteCols returns the AtlasCols for a palette entry, defaulting to 1
// so plain (single-cell) sprites render cleanly without the server having
// to fill the field at every call site.
func paletteCols(e PaletteEntry) int32 {
	if e.AtlasCols <= 0 {
		return 1
	}
	return e.AtlasCols
}

// paletteTileSize returns the entry's TileSize defaulting to 32 — the
// canonical Boxland cell size.
func paletteTileSize(e PaletteEntry) int32 {
	if e.TileSize <= 0 {
		return 32
	}
	return e.TileSize
}

// procIncludeAttr is the data-bx-proc-include attribute value for the
// palette tile. "1" / "0" so the JS toggle can read it as a flag without
// parsing booleans.
func procIncludeAttr(e PaletteEntry) string {
	if e.ProceduralInclude {
		return "1"
	}
	return "0"
}

// procIncludeTitle is the include-toggle button's tooltip.
func procIncludeTitle(e PaletteEntry) string {
	if e.ProceduralInclude {
		return "Tile is included in procedural fill — click to exclude"
	}
	return "Tile is excluded from procedural fill — click to include"
}

// paletteEntryClass adds the muted class when the tile is excluded so
// the CSS can fade it out without the JS having to do it on every render.
func paletteEntryClass(e PaletteEntry) string {
	if !e.ProceduralInclude {
		return "bx-mapmaker__palette__entry bx-mapmaker__palette__entry--excluded"
	}
	return "bx-mapmaker__palette__entry"
}

// paletteThumbStyle builds the CSS background-image + background-position
// + background-size that clips the source PNG to the right 32x32 cell.
//
// Tile sheet of cols x rows: the inner element is sized to one cell,
// the background-image is the full sheet scaled by `cols * thumbSize`
// (so each cell ends up exactly thumbSize px), and background-position
// shifts left by `col * thumbSize` and up by `row * thumbSize`.
//
// Single-cell sprites (cols=1) render as a plain background-image,
// no shift. The math collapses naturally — no special case needed.
//
// Pixel-art crispness comes from .bx-pixel { image-rendering:
// pixelated }, which is on the wrapping span.
func paletteThumbStyle(e PaletteEntry) string {
	cols := int(paletteCols(e))
	idx := int(e.AtlasIndex)
	col := idx % cols
	row := idx / cols
	thumb := 32 // CSS px the thumbnail occupies; matches palette grid
	totalW := thumb * cols
	// We don't know rows reliably from the palette payload, so size
	// the background by width and let height be auto — the browser
	// preserves aspect ratio and only the visible 32x32 window is
	// shown anyway.
	return fmt.Sprintf(
		"background-image:url('%s');background-repeat:no-repeat;background-size:%dpx auto;background-position:-%dpx -%dpx;",
		e.SpriteURL, totalW, col*thumb, row*thumb,
	)
}

